import type { AgentColor, AgentExpertise, AgentKbRefs, AgentModel, AgentSpec } from '@haive/shared';
import { QA_LENS_NUMBERED } from '../_qa-lenses.js';

// Re-export the canonical types so existing worker imports keep working without
// touching every call site. Source of truth lives in @haive/shared.
export type { AgentColor, AgentExpertise, AgentKbRefs, AgentModel, AgentSpec };

/** Bump when rendering semantics change without changing an AgentSpec. Used by
 * built-in and custom-bundle artifact hashes so onboarding-upgrade can refresh
 * provider-specific files generated by an older renderer. */
export const AGENT_RENDERER_VERSION = 2;

/** A CLI-specific destination for generated agent instructions. */
export interface AgentRenderTarget {
  dir: string;
  format: 'markdown' | 'toml';
  /** Explicitly supplied from the provider catalog. Legacy Codex TOML targets
   *  default to false below so pre-capability detect outputs are also safe. */
  supportsLsp?: boolean;
}

