// Complements SEARCH_ORDER_BLOCK (which trims READ tokens): a WRITE-side
// directive that keeps agent output concise to save subscription token
// allowance. Injected into every working agent except the document-producing
// ones in RESPONSE_STYLE_EXEMPT_IDS, whose deliverables must stay thorough.
const RESPONSE_STYLE_BLOCK = [
  '## Response Style',
  '',
  'Be concise. Lead with the answer, then only the reasoning that matters. Drop filler and',
  'do not restate the question. Prefer fragments and lists over prose paragraphs.',
  '',
  'Exceptions — be as thorough as the task needs when writing a specification, requirements,',
  'a migration, or a security finding; when explaining a multi-step plan; or when producing',
  'user-facing documentation.',
  '',
  'Never compress structured output: emit JSON, code, diffs, and any required format exactly',
  'as specified.',
].join('\n');

// Agents whose entire job is to produce thorough, descriptive deliverables.
// They must NOT receive the terseness directive.
const RESPONSE_STYLE_EXEMPT_IDS = new Set<string>([
  'technical-spec-writer',
  'business-requirements-writer',
  'spec-quality-reviewer',
  'docs-writer',
  'markdown-humanizer',
  'accessibility-specialist',
]);

function firstCharLower(s: string): string {
  return s.length === 0 ? s : s.charAt(0).toLowerCase() + s.slice(1);
}

function yamlKbRefs(refs: AgentKbRefs): string[] {
  const out: string[] = ['kb-references:'];
  if (refs.patterns) out.push(`  patterns: ${refs.patterns}`);
  if (refs.standards) out.push(`  standards: ${refs.standards}`);
  if (refs.reference) out.push(`  reference: ${refs.reference}`);
  return out.length === 1 ? [] : out;
}

function buildAgentBody(spec: AgentSpec, supportsLsp = true): string {
  const responseStyle = RESPONSE_STYLE_EXEMPT_IDS.has(spec.id) ? [] : [RESPONSE_STYLE_BLOCK, ''];
  const body: string[] = [
    `# ${spec.title}`,
    '',
    `You are the **${spec.title}**, a specialized agent that ${firstCharLower(spec.description)}`,
    '',
    ...responseStyle,
    '## Core Mission',
    '',
    spec.coreMission,
    '',
    '## Core Responsibilities',
    '',
    ...spec.responsibilities.map((r, i) => `${i + 1}. ${r}`),
    '',
    '## When You Are Invoked',
    '',
    'You are invoked when:',
    ...spec.whenInvoked.map((w) => `- ${w}`),
    '',
    '## Execution Protocol',
    '',
    supportsLsp ? SEARCH_ORDER_BLOCK_WITH_LSP : SEARCH_ORDER_BLOCK_WITHOUT_LSP,
    '',
    ...spec.executionSteps.flatMap((s, i) => [`### Step ${i + 1}: ${s.title}`, '', s.body, '']),
    '## Output Format',
    '',
    spec.outputFormat,
    '',
    '## Quality Criteria',
    '',
    'Before completing, verify:',
    ...spec.qualityCriteria.map((q) => `- [ ] ${q}`),
    '',
    '## Anti-Patterns',
    '',
    ...spec.antiPatterns.map((a) => `- **DO NOT** ${a}`),
    '',
  ];
  return body.join('\n');
}

export function buildAgentFileMarkdown(
  spec: AgentSpec,
  options: { supportsLsp?: boolean } = {},
): string {
  const frontmatter = [
    '---',
    `name: ${spec.id}`,
    `description: ${spec.description}`,
    `model: ${spec.model ?? 'opus'}`,
    `color: ${spec.color}`,
    `field: ${spec.field}`,
    `expertise: ${spec.expertise ?? 'expert'}`,
    `allowed-tools: [${spec.tools.join(', ')}]`,
    // Every agent gets `rag_search` so the Mandatory Search Order (RAG first)
    // is callable; any agent-specific MCP tools (e.g. chrome-devtools) merge in.
    `mcp-tools: [${Array.from(new Set(['rag_search', ...(spec.mcpTools ?? [])])).join(', ')}]`,
    'auto-invoke: false',
    ...(spec.kbReferences ? yamlKbRefs(spec.kbReferences) : []),
    '---',
    '',
  ].join('\n');

  return frontmatter + buildAgentBody(spec, options.supportsLsp ?? true);
}

/** Gemini CLI subagent format. Gemini's frontmatter parser rejects any key
 *  outside its own schema (`name`, `description`, `kind`, `tools`, `model`,
 *  `temperature`, `max_turns`, `timeout_mins`, `mcpServers`); emitting Claude
 *  keys like `color` or `allowed-tools` triggers "Unrecognized key(s)"
 *  warnings on every gemini run. We emit only the two required keys and let
 *  everything else inherit from the parent session (tools, model, MCP
 *  servers). The body is shared with the Claude renderer. */
export function buildAgentFileMarkdownGemini(
  spec: AgentSpec,
  options: { supportsLsp?: boolean } = {},
): string {
  const frontmatter = [
    '---',
    `name: ${spec.id}`,
    `description: ${spec.description}`,
    '---',
    '',
  ].join('\n');

  return frontmatter + buildAgentBody(spec, options.supportsLsp ?? false);
}

/** Gemini CLI loads every `*.md` file in `.gemini/agents/` as an agent
 *  definition and errors if frontmatter is missing — so an index README
 *  triggers "Missing mandatory YAML frontmatter" on every run. Claude and
 *  Codex both ignore non-agent files in their dirs, so the README is only
 *  problematic for gemini. */
export function shouldEmitAgentsReadme(target: { dir: string }): boolean {
  return target.dir !== '.gemini/agents';
}

/** Route an `AgentSpec` to the right serializer for a given target directory
 *  + format combination. Single decision point so 07-generate-files and the
 *  template-manifest renderer can't drift. */
export function buildAgentFileForTarget(spec: AgentSpec, target: AgentRenderTarget): string {
  // Old persisted detect outputs do not carry supportsLsp. Infer only the one
  // known LSP-capable legacy directory; Gemini, Codex, Antigravity and unknown
  // targets fail closed. Explicit capability metadata always wins.
  const supportsLsp = target.supportsLsp ?? target.dir === '.claude/agents';
  if (target.format === 'toml') return buildAgentFileToml(spec, { supportsLsp });
  if (target.dir === '.gemini/agents') return buildAgentFileMarkdownGemini(spec, { supportsLsp });
  return buildAgentFileMarkdown(spec, { supportsLsp });
}

function tomlBasicString(value: string): string {
  return `"${value.replace(/\\/g, '\\\\').replace(/"/g, '\\"')}"`;
}

function tomlMultilineBasicString(value: string): string {
  const escaped = value.replace(/\\/g, '\\\\').replace(/"""/g, '\\"\\"\\"');
  return `"""\n${escaped}\n"""`;
}

/** Emit a Codex-compatible agent definition as TOML.
 *  Schema (per https://developers.openai.com/codex/subagents):
 *    name                   — required, string
 *    description            — required, string (when/how Codex uses the agent)
 *    developer_instructions — required, multiline string (system prompt body)
 *  Optional fields (model, model_reasoning_effort, sandbox_mode, mcp_servers)
 *  are omitted so the agent inherits from the parent session. */
export function buildAgentFileToml(
  spec: AgentSpec,
  options: { supportsLsp?: boolean } = {},
): string {
  const instructions = buildAgentBody(spec, options.supportsLsp ?? false);
  return [
    `name = ${tomlBasicString(spec.id)}`,
    `description = ${tomlBasicString(spec.description)}`,
    `developer_instructions = ${tomlMultilineBasicString(instructions)}`,
    '',
  ].join('\n');
}

