          '    const fg = rgb(style.color) || [0,0,0];',
          '    return {',
          '      tag: el.tagName.toLowerCase(),',
          "      visible: rect.width > 0 && rect.height > 0 && style.display !== 'none' && style.visibility !== 'hidden' && style.opacity !== '0',",
